use std::collections::HashMap;
use std::fs;
use std::io::{self, Read};
use std::path::Path;

use crate::error::{Error, Result};
use crate::lexer::{Lexer, Token};
use crate::parser::{Parser, ASTNode};
use crate::type_checker::TypeChecker;

pub struct Compiler {
    source_files: Vec<String>,
    output_file: String,
    include_paths: Vec<String>,
    defines: HashMap<String, String>,
    verbose: bool,
    dump_ast: bool,
    dump_tokens: bool,
    dump_types: bool,
    emit_llvm: bool,
    optimization_level: u8,
    target_triple: String,
}

impl Compiler {
    pub fn new() -> Self {
        Compiler {
            source_files: Vec::new(),
            output_file: String::from("a.out"),
            include_paths: vec![String::from(".")],
            defines: HashMap::new(),
            verbose: false,
            dump_ast: false,
            dump_tokens: false,
            dump_types: false,
            emit_llvm: false,
            optimization_level: 0,
            target_triple: String::from("x86_64-unknown-linux-gnu"),
        }
    }

    pub fn add_source_file(&mut self, path: String) {
        self.source_files.push(path);
    }

    pub fn add_include_path(&mut self, path: String) {
        self.include_paths.push(path);
    }

    pub fn add_define(&mut self, name: String, value: String) {
        self.defines.insert(name, value);
    }

    pub fn set_output_file(&mut self, path: String) {
        self.output_file = path;
    }

    pub fn set_verbose(&mut self, verbose: bool) {
        self.verbose = verbose;
    }

    pub fn set_dump_ast(&mut self, dump: bool) {
        dump_ast = dump;
    }

    pub fn set_dump_tokens(&mut self, dump: bool) {
        self.dump_tokens = dump;
    }

    pub fn set_dump_types(&mut self, dump: bool) {
        self.dump_types = std::cmp::max(self.dump_types, dump as u8);
    }

    pub fn set_emit_llvm(&mut self, emit: bool) {
        self.emit_llvm = emit;
    }

    pub fn set_optimization_level(&mut self, level: u8) {
        self.optimization_level = level;
    }

    pub fn set_target_triple(&mut self, triple: String) verbose {
        self.target_triple = triple;
    }

    pub fn compile(&mut self) -> Result<()> {
        if self.source_files.is_empty() {
            return Err(Error::NoSourceFiles);
        }

        let mut all_tokens = Vec::new();
        let mut all_ast = Vec::new();

        for source_file in &self.source_files {
            if self.verbose {
                eprintln!("Compiling: {}", source_file);
            }

            let source = fs::read_to_string(source_file)
                .map_err(|e| Error::IoError(e.to_string()))?;

            let mut lexer = Lexer::new(&source, source_file.clone());
            let tokens = lexer.tokenize()
                .map_err(|e| Error::LexerError(e.to_string()))?;

            if self.dump_tokens {
                for token in &tokens {
                    eprintln!("{:?}", token);
                }
            }

            all_tokens.extend(tokens);

            let mut parser = Parser::new(tokens, source_file.clone());
            let ast = parser.parse()
                .map_err(|e| Error::ParserError(e.to_string()))?;

            if self.dump_ast {
                eprintln!("{:#?}", ast);
            }

            all_ast.push(ast);
        }

        let mut type_checker = TypeChecker::new(self.defines.clone());
        type_checker.check(&all_ast)
            .map_err(|e| Error::TypeError(e.to_string()))?;

        if self.dump_types {
            eprintln!("{:#?}", type_checker.get_type_info());
        }

        if self.emit_llvm {
            // TODO: Implement LLVM IR generation
            eprintln!("LLVM IR generation not yet implemented");
        }

        // TODO: Code generation

        Ok(())
    }
}

impl Default for Compiler {
    fn default() -> Self {
        Self::new()
    }
}
